mapper.select:
SELECT /* @SQLID=SUB020302_0301-01#Sql001 */ * FROM ( SELECT count(*) over() AS totalRow , DATE_YMD AS dateYmd , BROKER_CODE AS brokerCode , BROKER_NAME AS brokerName , DEALER_NUMBER AS dealerNumber , BROKER_CHARGE_CODE AS empCode , BROKER_CHARGE_NAME AS brokerChargeName , CUSTOMER_ATTRIBUTE AS customerAttribute , CUSTOMER_ATTRIBUTE_NAME AS courceName , BUTEN_CODE AS buten , ACCOUNT_NUMBER AS accountNumber , NAME_KANJI AS customerNameKanji , NAME_KANA AS customerNameKana , PRODUT_CD AS productCd , PRODUT_NAME AS securiytClass , BRAND_CODE AS brandCodeCurrency , BRAND_NAME AS brandName , TRADE_CD AS tradeCd , TRADE_NAME AS tradeTypeName , BALANCE_TYPE AS balanceType , DEPOSIT_NAME AS depositName , DEPOSIT_TYPE AS depositType , COUNTRY_CODE AS countryCode , BROKER_BRANCH_CODE AS branchCode , BROKER_BRANCH_NAME AS branchName , ACQUIRE_PRICE AS acquirePrice , APPRAISE_MARKET_PRICE AS appraiseMarketPrice , APPRAISE_PROFIT_LOSS_PRICE AS appraiseProfitLossPrice , EXEC_BASE_BALANCE AS contractStandardDeposit , CURRENCT_PRICE AS currentPrice , CURRENCY AS currency , FOREIGN_CURRENCT_PRICE AS foreignValuation , EXCHANGE_RATE AS fxRate , CASE DISPLAY_LAST_TRADE_DATE WHEN '99991231' THEN '----/--/--' ELSE TO_CHAR(TO_DATE(DISPLAY_LAST_TRADE_DATE, 'YYYY/MM/DD'), 'YYYY/MM/DD') END AS lastTradeDate , CASE WHEN SBI_LAST_TRADE_DATE IS NULL THEN NULL WHEN DISPLAY_LAST_TRADE_DATE <= SBI_LAST_TRADE_DATE THEN '-' ELSE TO_CHAR(TO_DATE(SBI_LAST_TRADE_DATE, 'YYYY/MM/DD'), 'YYYY/MM/DD') END AS sbiSecurityLastTradeDate , VISIBLE_BUTEN_CODE AS butenCodeViewAble
, FOREIGN_BOND_EVALUATE_DATE AS foreignStandardDate , SHIKUMI_SAI_KBN AS structuredBondClassification
FROM ( SELECT VBB.*, SDCR.VISIBLE_BUTEN_CODE FROM ( SELECT VB.DATE_YMD AS DATE_YMD , VB.BROKER_CODE AS BROKER_CODE , VB.BROKER_NAME AS BROKER_NAME , VB.DEALER_NUMBER AS DEALER_NUMBER , VB.BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE , VB.BROKER_CHARGE_CODE AS BROKER_CHARGE_CODE , VB.BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME , VB.CUSTOMER_ATTRIBUTE AS CUSTOMER_ATTRIBUTE , VB.CUSTOMER_ATTRIBUTE_NAME AS CUSTOMER_ATTRIBUTE_NAME , VB.BUTEN_CODE AS BUTEN_CODE , VB.ACCOUNT_NUMBER AS ACCOUNT_NUMBER , MUAI.NAME_KANJI AS NAME_KANJI , MUAI.NAME_KANA AS NAME_KANA , VB.PRODUT_CD AS PRODUT_CD , VB.PRODUT_NAME AS PRODUT_NAME , VB.BRAND_CODE AS BRAND_CODE , VB.BRAND_NAME AS BRAND_NAME , VB.TRADE_CD AS TRADE_CD , VB.TRADE_NAME AS TRADE_NAME , VB.BALANCE_TYPE AS BALANCE_TYPE , VB.DEPOSIT_NAME AS DEPOSIT_NAME , VB.DEPOSIT_TYPE AS DEPOSIT_TYPE , VB.COUNTRY_CODE AS COUNTRY_CODE , MB.BRANCH_NAME AS BROKER_BRANCH_NAME , VB.ACQUIRE_PRICE AS ACQUIRE_PRICE , VB.APPRAISE_MARKET_PRICE AS APPRAISE_MARKET_PRICE , VB.APPRAISE_PROFIT_LOSS_PRICE AS APPRAISE_PROFIT_LOSS_PRICE , VB.EXEC_BASE_BALANCE AS EXEC_BASE_BALANCE , VB.CURRENCT_PRICE AS CURRENCT_PRICE , VB.CURRENCY AS CURRENCY , VB.FOREIGN_CURRENCT_PRICE AS FOREIGN_CURRENCT_PRICE , VB.EXCHANGE_RATE AS EXCHANGE_RATE , VB.DISPLAY_LAST_TRADE_DATE AS DISPLAY_LAST_TRADE_DATE , VB.SBI_LAST_TRADE_DATE AS SBI_LAST_TRADE_DATE
, VB.FOREIGN_BOND_EVALUATE_DATE AS FOREIGN_BOND_EVALUATE_DATE , ZSFM.SHIKUMI_SAI_KBN AS SHIKUMI_SAI_KBN
FROM ( V_BALANCE VB LEFT OUTER JOIN MEDIATE_BRANCH MB ON VB.BROKER_CODE = MB.BROKER_CODE AND VB.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON VB.BUTEN_CODE = MUAI.BUTEN_CODE AND VB.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER AND VB.BROKER_CODE = MUAI.BROKER_CODE LEFT OUTER JOIN ZERO_STAR_F_MASTER ZSFM ON VB.BRAND_CODE = ZSFM.KOYU_CD ) WHERE 1=1
AND VB.BUTEN_CODE = #{req.butenCode}
AND VB.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND VB.DATE_YMD between TO_CHAR(TO_DATE(#{req.periodYm}, 'YYYYMM'), 'YYYYMMDD') and TO_CHAR(LAST_DAY(TO_DATE(#{req.periodYm}, 'YYYYMM')), 'YYYYMMDD')
AND LPAD(VB.BRAND_CODE,12,'0') = LPAD(#{req.brandCode},12,'0')
AND VB.BROKER_BRANCH_CODE = #{req.branchCode}
AND VB.BROKER_CODE NOT IN
AND VB.BROKER_CODE IN
#{item}
AND VB.BROKER_CHARGE_CODE = #{req.empCode}
AND (VB.BROKER_CODE IN
) OR VB.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
AND ((VB.BROKER_CODE, VB.BROKER_CHARGE_CODE) IN
) OR (VB.BROKER_CODE, VB.BROKER_CHARGE_CODE) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND ( MUAI.NAME_KANJI = #{req.customerName} OR MUAI.NAME_KANA = #{req.customerName} )
AND ( MUAI.NAME_KANJI LIKE #{req.customerName} || '%' OR MUAI.NAME_KANA LIKE #{req.customerName} || '%' )
AND ( MUAI.NAME_KANJI LIKE '%' || #{req.customerName} || '%' OR MUAI.NAME_KANA LIKE '%' || #{req.customerName} || '%' )
AND VB.CUSTOMER_ATTRIBUTE IN
#{item.id}
AND (
VB.PRODUT_CD IN
#{item.id}
OR
VB.PRODUT_CD IN
#{item.id}
) ) VBB LEFT OUTER JOIN SUB_DEALER_CODE_RELATION_IFAP SDCR ON VBB.ACCOUNT_NUMBER=SDCR.ACCOUNT_NUMBER AND VBB.BUTEN_CODE=SDCR.BUTEN_CODE WHERE 1=1
AND SDCR.VISIBLE_BUTEN_CODE IN
#{item}
)
ORDER BY BROKER_CODE ASC, BUTEN_CODE ASC, ACCOUNT_NUMBER ASC
ORDER BY BUTEN_CODE ASC, ACCOUNT_NUMBER ASC
) WHERE ROWNUM <= #{req.rownum}
